boot.shared:
import RAPIER from 'https://cdn.jsdelivr.net/npm/@dimforge/rapier2d-compat@0.19.3/+esm';
await RAPIER.init(); // 必须先 await:编译内联 base64 WASM
const g = data.gravity ?? { x: 0, y: -9.81 };
const world = new RAPIER.World(g);
for (const b of data.bodies) {
  const desc = (RAPIER.RigidBodyDesc[b.type] ?? RAPIER.RigidBodyDesc.dynamic)().setTranslation(b.translation.x, b.translation.y);
  const body = world.createRigidBody(desc);
  const c = b.collider;
  const cd = c.shape === 'ball' ? RAPIER.ColliderDesc.ball(c.radius)
    : c.shape === 'capsule' ? RAPIER.ColliderDesc.capsule(c.halfHeight, c.radius)
    : RAPIER.ColliderDesc.cuboid(c.hx, c.hy);
  if (b.restitution != null) cd.setRestitution(b.restitution);
  if (b.density != null) cd.setDensity(b.density);
  world.createCollider(cd, body);
}
// 每帧:world.step(); 读 body.translation()->{x,y}、body.rotation()->弧度,交给 canvas/pixi/three 画
